namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string CourseCode { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, quantities, shapes, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and human civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", CourseCode = "CS101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She specializes in programming pedagogy and curriculum design.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", CourseCode = "CS201", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is a researcher in algorithm optimization with publications in ACM and IEEE conferences.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", CourseCode = "CS310", Description = "Design and implementation of relational databases. Covers SQL, normalization, indexing, and transaction processing.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. She focuses on distributed database systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", CourseCode = "MATH101", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", CourseCode = "MATH202", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Zhang", InstructorBio = "Dr. Zhang researches applications of linear algebra in machine learning and data science.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Mechanics", CourseCode = "PHYS101", Description = "Newtonian mechanics including kinematics, dynamics, energy, and momentum. Laboratory component included.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster brings real-world physics applications into the classroom with engaging demonstrations.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, Title = "Electromagnetism", CourseCode = "PHYS202", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Nina Patel", InstructorBio = "Dr. Patel is an expert in electromagnetic theory with industry experience in telecommunications.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, Title = "English Composition", CourseCode = "ENG101", Description = "Develop critical reading and writing skills. Focus on argument construction, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. David Harrison", InstructorBio = "Prof. Harrison is a published author and writing coach who has mentored hundreds of student writers.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", CourseCode = "ENG220", Description = "Survey of major American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has written extensively on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History to 1500", CourseCode = "HIST101", Description = "Survey of world civilizations from ancient times through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Reed", InstructorBio = "Dr. Reed is an archaeologist and historian whose fieldwork spans three continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application this would persist to a database.
        return request.CourseId > 0
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

