@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p class="lead">Explore our departments and courses. Find the right classes for your academic journey.</p>
    </div>

    <section class="featured-section">
        <h2>Featured Courses</h2>
        <div class="course-grid">
            @foreach (var course in _featuredCourses)
            {
                <div class="course-card featured">
                    <span class="badge">@course.CourseCode</span>
                    <h3>@course.Title</h3>
                    <p>@course.Credits Credits &bull; @course.DepartmentName</p>
                    <p class="course-description">@course.Description</p>
                    <a href="/courses/@course.Id" class="btn btn-primary">View Details</a>
                </div>
            }
        </div>
    </section>

    <section class="departments-section">
        <h2>Departments</h2>
        <div class="department-grid">
            @foreach (var dept in _departments)
            {
                <div class="department-card">
                    <h3>@dept.Name</h3>
                    <p class="dept-code">@dept.Code</p>
                    <p>@dept.Description</p>
                    <a href="/courses?departmentId=@dept.Id" class="btn btn-secondary">Browse Courses</a>
                </div>
            }
        </div>
    </section>

    <section class="quick-links">
        <a href="/courses" class="btn btn-primary">Browse All Courses</a>
        <a href="/enroll" class="btn btn-secondary">Enrollment Request</a>
    </section>
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog - Browse Courses</PageTitle>

<div class="container">
    <h1>Course Catalog</h1>

    <div class="filters">
        <div class="filter-group">
            <label for="search">Search</label>
            <input id="search" type="text" placeholder="Search by title, code, or instructor..."
                   @bind="SearchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
        </div>
        <div class="filter-group">
            <label for="department">Department</label>
            <select id="department" @bind="SelectedDepartmentId" @bind:after="ApplyFilters">
                <option value="0">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (_courses.Any())
    {
        <div class="course-grid">
            @foreach (var course in _courses)
            {
                <div class="course-card">
                    <span class="badge">@course.CourseCode</span>
                    <h3>@course.Title</h3>
                    <p><strong>@course.Credits Credits</strong> &bull; @course.DepartmentName</p>
                    <p class="schedule">@course.Schedule</p>
                    <p class="instructor">Instructor: @course.InstructorName</p>
                    <a href="/courses/@course.Id" class="btn btn-primary">View Details</a>
                </div>
            }
        </div>
    }
    else
    {
        <p class="no-results">No courses found matching your criteria.</p>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }
    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        SelectedDepartmentId = DepartmentId ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        _courses = CatalogService.GetCourses(SearchTerm, SelectedDepartmentId > 0 ? SelectedDepartmentId : null);
    }
}

