                <div class="info-card">
                    <h3>Credits</h3>
                    <p class="info-value">@_course.Credits</p>
                </div>
                <div class="info-card">
                    <h3>Schedule</h3>
                    <p class="info-value">@_course.Schedule</p>
                </div>
