        _course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request - Course Catalog</PageTitle>

<div class="container">
    <h1>Enrollment Request</h1>
    <p>Submit a request to enroll in a course. You will receive a confirmation from the registrar's office.</p>

    @if (_submitted)
    {
        <div class="success-message">
            <h2>Request Submitted Successfully</h2>
            <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
                <strong>@_courses.FirstOrDefault(c => c.Id == _model.CourseId)?.Title</strong>
                has been received.</p>
            <p>The registrar's office will process your request and contact you at your university email.</p>
            <a href="/courses" class="btn btn-primary">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="enrollment-form">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="form-group">
                <label for="studentName">Full Name</label>
                <InputText id="studentName" @bind-Value="_model.StudentName" placeholder="Enter your full name" />
                <ValidationMessage For="() => _model.StudentName" />
            </div>

            <div class="form-group">
                <label for="studentId">Student ID</label>
                <InputText id="studentId" @bind-Value="_model.StudentId" placeholder="e.g., CS123456" />
                <ValidationMessage For="() => _model.StudentId" />
            </div>

            <div class="form-group">
                <label for="courseSelect">Course</label>
                <InputSelect id="courseSelect" @bind-Value="_model.CourseId">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in _courses)
                    {
                        <option value="@course.Id">@course.CourseCode - @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => _model.CourseId" />
            </div>

            <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest _model { get; set; } = new();

    private List<Course> _courses = new();
    private bool _submitted;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (CourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        _submitted = CatalogService.SubmitEnrollmentRequest(_model);
    }
}

